import { notification } from "antd";
import "antd/dist/antd.css";
import { pipe } from "fp-ts/lib/function";
import * as TE from "fp-ts/lib/TaskEither";
import "geoportal-extensions-leaflet/dist/GpPluginLeaflet";
import "geoportal-extensions-leaflet/dist/GpPluginLeaflet.css";
import { LatLngTuple } from "leaflet";
import React, {
  useCallback,
  useEffect,
  useRef,
  useState
} from "react";
import { Map, Polyline } from "react-leaflet";
import { getFlightData } from "../flightData";
import { Chart } from "./CustomChart";
import { OpenStreetMapLayer } from "./layer";
import LocateControl from "./LocateControl";

const defaultLatLng: LatLngTuple = [43.5, 3.95];
const zoom: number = 11;

type LeafletMapProps = {
  displayLFMT: boolean;
};

export const LeafletMap = ({ displayLFMT }: LeafletMapProps) => {
  const [lines, setLines] = useState<LatLngTuple[] | null>(null);
  const [mapLoaded, setMapLoaded] = useState<boolean>(false);
  // const mapRef = useRef<LeafletInternalMap>(null);
  const [mapRef, setMapRef] = useState<Map | null>(null);
  const onRefChange = useCallback((node) => {
    // ref value changed to node
    setMapRef(node); // e.g. change ref state to trigger re-render
    if (node === null) {
      // node is null, if DOM node of ref had been unmounted before
    } else {
      // ref value exists
      console.log(node);
      setMapLoaded(true);
    }
  }, []);

  const pathRef = useRef<Polyline>(null);
  const openNotificationWithIcon = ({
    title,
    message,
  }: {
    title: string;
    message: string;
  }) => {
    notification["warning"]({
      message: title,
      description: message,
    });
  };

  useEffect(() => {
    pipe(
      getFlightData("20201019-164100.txt"),
      TE.fold(
        (e) => async () => {
          console.error(e);
          if (e instanceof Error) {
            console.error(e);
            openNotificationWithIcon({ title: "Error", message: e.message });
          }
        },
        (row) => async () => {
          setLines(row);
        },
      ),
    )();
  }, []);
  const leafletMap = mapRef?.leafletElement;
  return (
    <Map id="mapId" ref={onRefChange} center={defaultLatLng} zoom={zoom}>
      <OpenStreetMapLayer />
      {/* <OaciLayer /> */}
      {displayLFMT && leafletMap && <Chart map={leafletMap} />}
      <LocateControl startDirectly={true} />
      {lines && (
        <Polyline
          ref={pathRef}
          opacity={10}
          color="black"
          positions={lines}
          className={"onTop"}
        />
      )}
    </Map>
  );
};
